defmodule MyApp.WebhookController do
  use MyApp.Web, :controller

  def fetch_url(conn, %{"url" => url}) do
    case HTTPoison.get(url) do
      {:ok, %HTTPoison.Response{status_code: 200, body: body}} ->
        conn
        |> put_resp_header("content-type", "text/plain")
        |> send_resp(200, body)
      {:error, %{reason: reason}} ->
        conn
        |> send_resp(500, "Error fetching URL: #{inspect reason}")
    end
  end

  defp fetch_url(conn, _) do
    conn
    |> send_resp(400, "Missing required 'url' parameter")
  end
end